const { v4: uuid } = require('uuid')

// simple append-only store (in-memory for demo)
const eventStore = new Map() // streamId -> [{id, type, payload, version}]

async function appendEvent(streamId, event, expectedVersion) {
  const stream = eventStore.get(streamId) || []
  const currentVersion = stream.length - 1
  if (expectedVersion != null && expectedVersion !== currentVersion) {
    throw new Error('Concurrency conflict')
  }
  const record = { id: uuid(), ...event, version: currentVersion + 1 }
  stream.push(record)
  eventStore.set(streamId, stream)
  return record
}

async function loadEvents(streamId) {
  return eventStore.get(streamId) || []
}

// usage
(async () => {
  await appendEvent('acct-123', { type: 'AccountOpened', payload: { balance: 0 } })
  await appendEvent('acct-123', { type: 'AccountCredited', payload: { amount: 100 } }, 0)
  const events = await loadEvents('acct-123')
  console.log('events:', events)
})()
